<template>
    <div id="problemset">
        <loadings :isLoading="settings.base.beforeLoad? 1: 0"></loadings>
        <div v-if="!settings.base.beforeLoad" >
            <NavBar :isActive="settings.base.belong" :isLogin="settings.base.isLogin" :user="settings.base.userInfo"></NavBar>
            <div class="container mundb-standard-container" style="min-height: 70vh">
                <div class="row">
                    <div class="col-sm-12 col-lg-9">
                        <paper-card class="animated bounceInLeft" style="min-height: 292px">
                            <div class="table-responsive">
                                <div style="text-align: center;margin-top: 90px;font-size: 25px;height: 150px;color: #dcdcdc"
                                     v-if="settings.problemSet.loading">
                                    <i class="fa fa-spinner fa-pulse fa-3x fa-fw"></i>
                                    <span class="sr-only">Loading...</span>
                                </div>
                                <template v-else>
                                    <table id="problems" class="table table-borderless">
                                        <thead>
                                        <tr>
                                            <th scope="col" style="width: 10%">
                                                <form class="form-inline"
                                                      style="margin-bottom: 0px" @submit.prevent="chooseProblemId()">
                                                    <input v-model="settings.problemSet.search.problemId" class="form-control search-query"
                                                           type="text" style="width: 100%;text-align: center"
                                                           name="pid" placeholder="ID">
                                                </form>
                                            </th>
                                            <th scope="col">
                                                <form class="form-inline" style="margin-bottom: 0px"
                                                      @submit.prevent="chooseTitle()">
                                                    <input v-model="settings.problemSet.search.title" type="text"
                                                           style="width:100%;text-align: center"
                                                           class="form-control search-query"
                                                           placeholder="Problems">
                                                </form>
                                            </th>
                                            <th scope="col" class="cm-fw" style="padding-bottom: 20px;">
                                                Solved
                                            </th>
                                            <th scope="col" class="cm-fw" style="padding-bottom: 20px;">
                                                Submit
                                            </th>
                                            <th scope="col" class="cm-fw" style="padding-bottom: 20px;">
                                                AC rate
                                            </th>
                                        </tr>
                                        </thead>
                                        <tbody>

                                        <tr v-for="saved_problem in result.problemSetForm.problems" v-bind:key="key">
                                            <th scope="row"> CTGAOJ{{saved_problem.problemId}}</th>
                                            <td>
                                                <template v-if="saved_problem.hasPass == 0">
                                                    <i style="color: lightgrey" class="fa fa-circle-o"
                                                       aria-hidden="true"></i>
                                                </template>
                                                <template v-else-if="saved_problem.hasPass == 2">
                                                    <i style="color: orange" class="fa fa-adjust" aria-hidden="true"></i>
                                                </template>
                                                <template v-else>
                                                    <i style="color: lightseagreen;" class="fa fa-circle"
                                                       aria-hidden="true"></i>
                                                </template>

                                                <span>{{" "}}</span>
                                                <a style="text-decoration:none;"
                                                   v-bind:href="'problem.html?pid='+ saved_problem.problemId">{{saved_problem.title}}</a>
                                            </td>
                                            <td> {{saved_problem.submitStatistics.allSubmitTimes}}</td>
                                            <td> {{saved_problem.submitStatistics.acSubmitTimes}}</td>
                                            <td> {{saved_problem.submitStatistics.allSubmitTimes == 0? "---":
                                                parseFloat(saved_problem.submitStatistics.acSubmitTimes*100/saved_problem.submitStatistics.allSubmitTimes).toFixed(2)+"%"}}
                                            </td>
                                        </tr>
                                        </tbody>
                                    </table>
                                    <empty-container v-if="problems != null && result.problemSetForm.problems.length <= 0">
                                        <svg t="1605936727818" class="icon" viewBox="0 0 1024 1024" version="1.1"
                                             xmlns="http://www.w3.org/2000/svg" p-id="3621" width="100" height="100">
                                            <path d="M576 928c-6 0-11.9-1.7-17.1-5-9.3-5.9-14.9-16.1-14.9-27V554.3c0-12.4 7.1-23.6 18.3-28.9l288-136.1c9.9-4.7 21.5-4 30.8 1.9s14.9 16.1 14.9 27v341.7c0 12.4-7.1 23.6-18.3 28.9l-288 136.1c-4.4 2.1-9 3.1-13.7 3.1z m32-353.5v271l224-105.8v-271L608 574.5zM448 928c-4.7 0-9.3-1-13.7-3.1l-288-136.1c-11.2-5.3-18.3-16.6-18.3-28.9V418.2c0-11 5.6-21.2 14.9-27 9.3-5.9 20.9-6.6 30.8-1.9l288 136.1c11.2 5.3 18.3 16.6 18.3 28.9V896c0 11-5.6 21.2-14.9 27-5.2 3.3-11.1 5-17.1 5zM192 739.7l224 105.8v-271L192 468.7v271zM512 501.1c-4.7 0-9.4-1-13.8-3.1l-352-168.1c-11.2-5.4-18.3-16.7-18.2-29.2 0.1-12.4 7.4-23.7 18.8-28.8l352-159.9c8.4-3.8 18.1-3.8 26.5 0l352 159.9c11.3 5.1 18.6 16.4 18.8 28.8 0.1 12.4-7 23.8-18.2 29.2L525.8 498c-4.4 2-9.1 3.1-13.8 3.1zM235.8 301.7L512 433.6l276.2-131.9L512 176.2 235.8 301.7z"
                                                  p-id="3622" fill="#7a8e97"></path>
                                        </svg>
                                        <p>Nothing matches.</p>
                                    </empty-container>
                                </template>


                            </div>
                        </paper-card>
                        <nav aria-label="..." class="animated bounceInLeft" style="min-height: 36px">
                            <ul class="pagination justify-content-center">
                                <li v-bind:class="{'page-item':true, 'disable': settings.problemSet.page <= 1}">
                                    <a class="page-link cm-navi" @click="switchPage(settings.problemSet.page-1)" href="javascript:void(0)">
                                        <i style="line-height: 18px;" v-bind:style="{'color': settings.problemSet.page <= 1? 'grey': ''}"
                                           class="material-icons prefix">chevron_left</i>
                                    </a>
                                </li>
                                <template v-if="settings.problemSet.maxPage <= 14">
                                    <li v-bind:class="{'page-item': true, 'active': i == settings.problemSet.page}"
                                        v-for="i in page_index_range(1, settings.problemSet.maxPage)" v-bind:key="key">
                                        <a v-if="settings.problemSet.page != i" class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                        <span v-else class="page-link">{{settings.problemSet.page}}</span>
                                    </li>
                                </template>
                                <template v-else>
                                    <template v-if="settings.problemSet.page < 7">
                                        <li v-bind:class="{'page-item': true, 'active': i == settings.problemSet.page}"
                                            v-for="i in page_index_range(1, settings.problemSet.page+3)" v-bind:key="key">
                                            <a v-if="settings.problemSet.page != i" class="page-link" href="javascript:(0)"
                                               @click="switchPage(i)">{{i}}</a>
                                            <span v-else class="page-link">{{settings.problemSet.page}}</span>
                                        </li>
                                        <li class="page-item disabled" aria-disabled="true"><span
                                                class="page-link">...</span>
                                        </li>
                                        <li class="page-item" v-for="i in page_index_range(settings.problemSet.maxPage-2, settings.problemSet.maxPage)"
                                            v-bind:key="key">
                                            <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                        </li>
                                    </template>
                                    <template v-else-if="settings.problemSet.page >= settings.problemSet.maxPage - 5">
                                        <li class="page-item" v-for="i in 3" v-bind:key="key">
                                            <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                        </li>
                                        <li class="page-item disabled" aria-disabled="true"><span
                                                class="page-link">...</span>
                                        </li>
                                        <li v-bind:class="{'page-item': true, 'active': i == settings.problemSet.page}"
                                            v-for="i in page_index_range(settings.problemSet.page-3, settings.problemSet.maxPage)"
                                            v-bind:key="key">
                                            <a v-if="settings.problemSet.page != i" class="page-link" href="javascript:(0)"
                                               @click="switchPage(i)">{{i}}</a>
                                            <span v-else class="page-link">{{settings.problemSet.page}}</span>
                                        </li>
                                    </template>
                                    <template v-else>
                                        <li class="page-item" v-for="i in 3" v-bind:key="key">
                                            <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                        </li>
                                        <li class="page-item disabled" aria-disabled="true"><span
                                                class="page-link">...</span>
                                        </li>
                                        <li v-bind:class="{'page-item': true, 'active': i == settings.problemSet.page}"
                                            v-for="i in page_index_range(settings.problemSet.page-3, settings.problemSet.page+3)"
                                            v-bind:key="key">
                                            <a v-if="settings.problemSet.page != i" class="page-link" href="javascript:(0)"
                                               @click="switchPage(i)">{{i}}</a>
                                            <span v-else class="page-link">{{settings.problemSet.page}}</span>
                                        </li>
                                        <li class="page-item disabled" aria-disabled="true"><span
                                                class="page-link">...</span>
                                        </li>
                                        <li class="page-item" v-for="i in page_index_range(settings.problemSet.maxPage-2, settings.problemSet.maxPage)"
                                            v-bind:key="key">
                                            <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                        </li>
                                    </template>
                                </template>
                                <li v-bind:class="{'page-item':true, 'disable': settings.problemSet.page >= settings.problemSet.maxPage}">
                                    <a class="page-link cm-navi" href="javascript:(0)" @click="switchPage(settings.problemSet.page+1)">
                                        <i style="line-height: 18px;" v-bind:style="{'color': settings.problemSet.page >= settings.problemSet.maxPage? 'grey': ''}"
                                           class="material-icons prefix">chevron_right</i>
                                    </a>
                                </li>
                            </ul>
                        </nav>
                    </div>
                    <div class="col-sm-12 col-lg-3">
                        <paper-card id="category-pannel" class="animated bounceInRight">
                            <div>
                                <p style="display: inline-block;white-space: pre">Category{{" "}}</p>
                                <a style="cursor: pointer" role="button" id="categoryContent" data-toggle="dropdown"
                                   aria-haspopup="true" aria-expanded="false">
                                    <i class="fa fa-bars" aria-hidden="true"></i>
                                </a>
                                <div id="category-menu" class="dropdown-menu" style="max-height: 350px; overflow-y: scroll;"
                                     aria-labelledby="categoryContent">
                                    <a style="cursor: pointer" v-for="(saved_category,key) in result.categoryForm.category" v-bind:key="key" class="dropdown-item"
                                       @click="switchCategory(key)">{{saved_category.main.name}}</a>
                                </div>
                            </div>
                            <template v-for="(saved_category,key) in result.categoryForm.category">
                                <div v-bind:key="key" v-if="settings.category.categoryPage == key">
                                    <template v-if="saved_category.root.length >= 1">
                                        <span class="badge badge-title badge-tag selected ">基本</span>
                                        <div style="clear:both"></div>
                                        <span v-for="saved_category_root in saved_category.root" v-bind:key="key"
                                              @click="chooseParm('category', forms.problemSetForm.category==saved_category_root.cateId? null:saved_category_root.cateId)"
                                              v-bind:class="{'badge':true, 'badge-tag':true, 'selected':getUrlKey('category')==saved_category_root.cateId}">{{saved_category_root.name}}</span>
                                        <div style="clear:both"></div>
                                    </template>
                                    <template v-if="saved_category.noroot.length >= 1">
                                        <template v-for="saved_category_noroot in saved_category.noroot">
                                            <span class="badge badge-tag badge-title selected " v-bind:key="key">{{saved_category_noroot.main.name}}</span>
                                            <div style="clear:both" v-bind:key="key"></div>
                                            <span v-for="saved_category_noroot_root in saved_category_noroot.root"
                                                  v-bind:key="key1"
                                                  @click="chooseParm('category', forms.problemSetForm.category==saved_category_noroot_root.cateId? null:saved_category_noroot_root.cateId)"
                                                  v-bind:class="{'badge':true, 'badge-tag':true, 'selected': getUrlKey('category')==saved_category_noroot_root.cateId}">{{saved_category_noroot_root.name}}</span>
                                            <div style="clear:both" v-bind:key="key"></div>
                                        </template>
                                    </template>
                                </div>
                            </template>
                        </paper-card>
                        <paper-card id="source-pannel" class="animated bounceInRight">
                            <div>
                                <p style="display: inline-block;white-space: pre">Source{{" "}}</p>
                                <a style="cursor: pointer" role="button" id="sourceContent" data-toggle="dropdown"
                                   aria-haspopup="true" aria-expanded="false">
                                    <i class="fa fa-bars" aria-hidden="true"></i>
                                </a>
                                <div id="source-menu" class="dropdown-menu" style="max-height: 350px; overflow-y: scroll;"
                                     aria-labelledby="sourceContent">
                                    <a style="cursor: pointer" v-for="(saved_source,key) in result.sourceForm.source" v-bind:key="key" class="dropdown-item"
                                       @click="switchSource(key)">{{saved_source.main.name}}</a>
                                </div>
                            </div>
                            <template v-for="(saved_source,key) in result.sourceForm.source">
                                <div v-bind:key="key" v-if="settings.source.sourcePage == key">
                                    <template v-if="saved_source.root.length >= 1">
                                        <span class="badge badge-title badge-tag selected ">基本</span>
                                        <div style="clear:both"></div>
                                        <span v-for="saved_source_root in saved_source.root" v-bind:key="key"
                                              @click="chooseParm('source', forms.problemSetForm.source==saved_source_root.sourceId? null:saved_source_root.sourceId)"
                                              v-bind:class="{'badge':true, 'badge-tag':true, 'selected': getUrlKey('source')==saved_source_root.sourceId}">{{saved_source_root.name}}</span>
                                        <div style="clear:both"></div>
                                    </template>
                                    <template v-if="saved_source.noroot.length >= 1">
                                        <template v-for="saved_source_noroot in saved_source.noroot">
                                            <span class="badge badge-tag badge-title selected " v-bind:key="key">{{saved_source_noroot.main.name}}</span>
                                            <div style="clear:both" v-bind:key="key"></div>
                                            <span v-for="saved_source_noroot_root in saved_source_noroot.root"
                                                  v-bind:key="key1"
                                                  @click="chooseParm('source', forms.problemSetForm.source==saved_source_noroot_root.sourceId? null:saved_source_noroot_root.sourceId)"
                                                  v-bind:class="{'badge':true, 'badge-tag':true, 'selected': getUrlKey('source')==saved_source_noroot_root.sourceId}">{{saved_source_noroot_root.name}}</span>
                                            <div style="clear:both" v-bind:key="key"></div>
                                        </template>
                                    </template>
                                </div>
                            </template>
                        </paper-card>
                    </div>
                </div>
            </div>
            <footers></footers>
        </div>
        <!--<navbar></navbar>-->

    </div>
</template>

<script>
    /* eslint no-useless-escape: "off"*/
    /* eslint vue/valid-v-for: "off"*/
    import NavBar from "@/components/navbar/navbar";
    import fun from '@/assets/js/OJFunction'
    import Footers from "@/components/footer/footer";
    import Loadings from "@/components/loading/loading";

    export default {
        components: {
            Loadings,
            Footers,
            NavBar
        },
        name: "problemset",
        data() {
            return {
                settings: {
                    base:{
                        belong: 'problemset',
                        beforeLoad: true,
                        isLogin: false,
                        user: new Object(),
                    },
                    category:{
                        categoryPage: 0,
                    },
                    source:{
                        sourcePage: 0,
                    },
                    problemSet:{
                        page: 0,
                        maxPage: 0,
                        loading: true,
                        search: {
                            problemId: null,
                            title: null
                        },
                    }
                },
                forms:{
                    problemSetForm:{
                        page: null,
                        source: '',
                        category: '',
                        title: '',
                    }
                },
                result:{
                    problemSetForm:{
                        problems: [],
                    },
                    categoryForm:{
                        category: [],
                    },
                    sourceForm:{
                        source: [],
                    }
                },
            }
        },
        methods: {
            page_index_range: function (a, b) {
                var res = [];
                for (var i = a; i <= b; i++) {
                    res.push(i);
                }
                return res;
            },
            switchPage: function (p) {
                if (p >= 1 && p <= this.settings.problemSet.maxPage) {
                    this.addUrlParm("page", p);
                    var url = "/problemset.html" + this.getUrlString();
                    window.location.href = url;
                }
            },
            chooseProblemId: function () {
                var pid = this.settings.problemSet.search.problemId;
                window.location.href = '/problem.html?pid=' + encodeURIComponent(pid);
            },
            chooseTitle: function (e) {
                this.addUrlParm("title", this.settings.problemSet.search.title);
                var url = "/problemset.html" + this.getUrlString();
                window.location.href = url;
                e.preventDefault();
            },
            getUrlKey: function (key) {
                return fun.getUrlKey(key);
            },
            addUrlParm: function (key, value) {
                if (fun.getUrlKey("source") != null) this.forms.problemSetForm.source = fun.getUrlKey("source");
                if (fun.getUrlKey("category") != null) this.forms.problemSetForm.category = fun.getUrlKey("category");
                if (fun.getUrlKey("title") != null) this.forms.problemSetForm.title = fun.getUrlKey("title");
                if (fun.getUrlKey("page") != null) this.forms.problemSetForm.page = fun.getUrlKey("page");

                if ("source" == key) this.forms.problemSetForm.source = value != null ? value : null;
                if ("category" == key) this.forms.problemSetForm.category = value != null ? value : null;
                if ("title" == key) this.forms.problemSetForm.title = value != null && value != "" ? value : null;
                if ("page" == key) this.forms.problemSetForm.page = value != null && value != "" ? value : null;
            },
            getUrlString: function () {
                var str = "";
                if (this.forms.problemSetForm.page != null) str += "&page=" + encodeURIComponent(this.forms.problemSetForm.page);
                if (this.forms.problemSetForm.source != null) str += "&source=" + encodeURIComponent(this.forms.problemSetForm.source);
                if (this.forms.problemSetForm.category != null) str += "&category=" + encodeURIComponent(this.forms.problemSetForm.category);
                if (this.forms.problemSetForm.title != null) str += "&title=" + encodeURIComponent(this.forms.problemSetForm.title);
                return str.replace("&", "?");
            },
            switchCategory: function (num) {
                this.settings.category.categoryPage = num;
            },
            switchSource: function (num) {
                this.settings.source.sourcePage = num;
            },
            chooseParm: function (key, val) {
                // this.$refs.load.loading_show();
                this.addUrlParm(key, val);
                var url = "/problemset.html" + this.getUrlString();
                window.location.href = url;
            },
            async refresh(){
                var _this = this
                setTimeout(async function () {
                    // console.log(1)
                    let data = await fun.refresh();
                    if (data.OJ_ERROR_TYPE == _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        _this.settings.base.isLogin = true;
                        _this.settings.base.userInfo = data.OJ_USER_INFO;
                    }else{
                        window.location.href = '/loginpage.html';
                    }
                    _this.refresh()
                }, 1000*60*20)
            },
            identify: async function () {
                let data = await fun.idenfity();
                this.$i18n.locale = data.OJ_LANGUAGE_TYPE;
                if (data.OJ_ERROR_TYPE == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                    this.settings.base.isLogin = true;
                    this.settings.base.userInfo = data.OJ_USER_INFO;
                }
                this.refresh()
                return data;
            },
            searchProblems() {
                var _this = this
                return window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/problem/list', {}, {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                })
            },
            searchCategory() {
                var _this = this
                return window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/category/list', {}, {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                })
            },
            searchSource() {
                var _this = this
                return window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/source/list', {}, {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                })
            },
        },
        async created() {
            await this.identify();
            this.settings.base.beforeLoad = false;

            this.forms.problemSetForm.page = fun.getUrlKey("page");
            this.forms.problemSetForm.source = fun.getUrlKey("source");
            this.forms.problemSetForm.category = fun.getUrlKey("category");
            this.forms.problemSetForm.title = this.settings.problemSet.search.title = fun.getUrlKey("title");

            var _this = this
            window.axios.all([_this.searchProblems(), _this.searchCategory(), _this.searchSource()])
                .then(window.axios.spread((ProblemRes, CategoryRes, SourceRes) => {
                    let ProblemData = ProblemRes.data, CategoryData = CategoryRes.data, SourceData = SourceRes.data;
                    _this.result.problemSetForm.problems = ProblemData.OJ_PROBLEM;
                    _this.settings.problemSet.page = ProblemData.OJ_PAGE_INDEX;
                    _this.settings.problemSet.maxPage = ProblemData.OJ_MAX_PAGE_INDEX;
                    _this.result.categoryForm.category = CategoryData.OJ_CATEGORY;
                    _this.result.sourceForm.source = SourceData.OJ_SOURCE;
                    _this.settings.problemSet.loading = false;
                    console.log(SourceData)
                }))
                .catch((error) => {
                    console.log(error)
                })
        }
    }
</script>

<style scoped lang="scss">

