        overflow-x: hidden;

        empty-container {
            display: block;
            text-align: center;
            margin-bottom: 4rem;
            margin-top: 4rem;

            p {
                margin-left: 20px;
                display: inline-block;
                font-size: 20px;
                font-weight: bold;
                font-family: "Roboto-slab";
            }
        }

        #source-pannel {
            .badge-tag {
                white-space: pre-line;
                text-align: unset;
                line-height: 15px;
                color: #6c757d;
                margin-right: 3px;
                background-color: transparent;
                /* max-width: 7rem; */
