            }
        }

        #category-pannel {
            .badge-tag {
                white-space: pre-line;
                text-align: unset;
                line-height: 15px;
                color: #03a9f4;
                margin-right: 3px;
                background-color: transparent;
                /* max-width: 7rem; */
                overflow: hidden;
                text-overflow: ellipsis;
                border: 1px solid #03a9f4;
                cursor: pointer;
            }

            .badge-tag.selected {
                color: white;
                background-color: #03a9f4;
            }

            .badge-title:not(:first-of-type) {
                margin-top: 20px;
            }
        }

        #category-menu {
            max-width: 30rem;
            min-width: 14rem;
        }

        #category-menu::-webkit-scrollbar, #source-menu::-webkit-scrollbar {
            width: 5px;
            height: 16px;
            background-color: #F5F5F5;
            border-radius: 4px;
        }
